const items = $input.all();

console.log('\n═══════════════════════════════════════════════════');
console.log('📊 STRUCTURATION NOTIFICATIONS - DEMANDES (XDMDRQ)');
console.log('═══════════════════════════════════════════════════');
console.log(`Lignes reçues: ${items.length}`);

const notifications = {};

items.forEach(item => {
  const d = item.json;
  let dest, codeKey, typeKey;

  if (d.niveau_escalade === 'PDG') {
    dest = { code: d.code_pdg, nom: d.nom_pdg, prenom: d.prenom_pdg, email: d.email_pdg, telephone: d.telephone_pdg, chat_id: d.chat_id_pdg, langue: d.langue_pdg, bot: d.bot_pdg };
    codeKey = d.code_pdg; typeKey = 'PDG';

  } else if (d.niveau_escalade === 'DGA') {
    dest = { code: d.code_dga, nom: d.nom_dga, prenom: d.prenom_dga, email: d.email_dga, telephone: d.telephone_dga, chat_id: d.chat_id_dga, langue: d.langue_dga, bot: d.bot_dga };
    codeKey = d.code_dga; typeKey = 'DGA';

  } else if (d.niveau_escalade === 'BAALLAH') {
    dest = { code: d.code_baallah, nom: d.nom_baallah, prenom: d.prenom_baallah, email: d.email_baallah, telephone: d.telephone_baallah, chat_id: d.chat_id_baallah, langue: d.langue_baallah, bot: d.bot_baallah };
    codeKey = d.code_baallah; typeKey = 'BAALLAH';

  } else if (d.niveau_escalade === 'SUPERIEUR') {
    dest = { code: d.code_superieur, nom: d.nom_superieur, prenom: d.prenom_superieur, email: d.email_superieur, telephone: d.tel_superieur, chat_id: d.chat_id_superieur, langue: d.langue_superieur, bot: d.bot_superieur };
    codeKey = d.code_superieur; typeKey = 'SUPERIEUR';

  } else if (d.niveau_escalade === 'SALARIE') {
    dest = { code: d.code_createur, nom: d.nom_createur, prenom: d.prenom_createur, email: d.email_createur, telephone: d.tel_createur, chat_id: d.chat_id_createur, langue: d.langue_createur, bot: d.bot_createur };
    codeKey = d.code_createur; typeKey = 'SALARIE';

  } else if (d.niveau_escalade === 'FARHAT') {
    dest = { code: d.code_farhat, nom: d.nom_farhat, prenom: d.prenom_farhat, email: d.email_farhat, telephone: d.telephone_farhat, chat_id: d.chat_id_farhat, langue: d.langue_farhat, bot: d.bot_farhat };
    codeKey = d.code_farhat; typeKey = 'FARHAT';

  } else {
    return;
  }

  const cleKey = `${typeKey}_${codeKey}`;

  if (!notifications[cleKey]) {
    notifications[cleKey] = {
      destinataire_principal: dest,
      type_destinataire: typeKey,
      niveau_escalade: d.niveau_escalade,
      createur_info: {
        code: d.code_createur, nom: d.nom_createur, prenom: d.prenom_createur,
        email: d.email_createur, telephone: d.tel_createur,
        chat_id: d.chat_id_createur, langue: d.langue_createur, bot: d.bot_createur
      },
      superieur: {
        code: d.code_superieur, nom: d.nom_superieur, prenom: d.prenom_superieur,
        email: d.email_superieur, telephone: d.tel_superieur,
        chat_id: d.chat_id_superieur, langue: d.langue_superieur, bot: d.bot_superieur
      },
      pdg:     { code: d.code_pdg,     nom: d.nom_pdg,     prenom: d.prenom_pdg,     email: d.email_pdg,     telephone: d.telephone_pdg,     chat_id: d.chat_id_pdg,     langue: d.langue_pdg,     bot: d.bot_pdg },
      dga:     { code: d.code_dga,     nom: d.nom_dga,     prenom: d.prenom_dga,     email: d.email_dga,     telephone: d.telephone_dga,     chat_id: d.chat_id_dga,     langue: d.langue_dga,     bot: d.bot_dga },
      farhat:  { code: d.code_farhat,  nom: d.nom_farhat,  prenom: d.prenom_farhat,  email: d.email_farhat,  telephone: d.telephone_farhat,  chat_id: d.chat_id_farhat,  langue: d.langue_farhat,  bot: d.bot_farhat },
      baallah: { code: d.code_baallah, nom: d.nom_baallah, prenom: d.prenom_baallah, email: d.email_baallah, telephone: d.telephone_baallah, chat_id: d.chat_id_baallah, langue: d.langue_baallah, bot: d.bot_baallah },
      demandes: []
    };
  }

  notifications[cleKey].demandes.push({
    num_demande:           d.num_demande,
    date_document:         d.date_document,
    code:                  d.code,
    matricule:             d.matricule,
    nom_prenom:            d.nom_prenom,
    date_embauche:         d.date_embauche,
    fonction:              d.fonction,
    date_creation:         d.date_creation,
    date_controle:         d.date_controle,
    date_limite:           d.date_limite,
    jours_depuis_creation: d.jours_depuis_creation,
    jours_restants:        d.jours_restants,
    delai_int:             d.delai_int,
    seuil_dga:             d.seuil_dga,
    createur: {
      code: d.code_createur, nom: d.nom_createur, prenom: d.prenom_createur,
      email: d.email_createur, telephone: d.tel_createur
    }
  });
});

const resultats = Object.values(notifications).map(notif => {
  const total    = notif.demandes.length;
  const joursMin = Math.min(...notif.demandes.map(s => s.jours_restants));
  const joursMax = Math.max(...notif.demandes.map(s => s.jours_restants));
  const delaiInt = notif.demandes[0]?.delai_int || 30;
  const seuilDga = notif.demandes[0]?.seuil_dga || Math.floor(delaiInt / 2);

  return {
    destinataire_principal: notif.destinataire_principal,
    type_destinataire:      notif.type_destinataire,
    niveau_escalade:        notif.niveau_escalade,
    createur_info:          notif.createur_info,
    superieur:              notif.superieur,
    pdg:                    notif.pdg,
    dga:                    notif.dga,
    farhat:                 notif.farhat,
    baallah:                notif.baallah,
    demandes:               notif.demandes,
    statistiques: {
      total_demandes: total,
      jours_min:      joursMin,
      jours_max:      joursMax,
      delai_int:      delaiInt,
      seuil_dga:      seuilDga
    },
    meta: {
      date_traitement:       new Date().toISOString(),
      peut_envoyer_email:    !!notif.destinataire_principal.email,
      peut_envoyer_telegram: !!notif.destinataire_principal.chat_id,
      langue_message:        notif.destinataire_principal.langue || 'FRA'
    }
  };
});

console.log(`\n✅ Groupes structurés: ${resultats.length}`);
['PDG','DGA','BAALLAH','SUPERIEUR','SALARIE','FARHAT'].forEach(t => {
  console.log(`  - ${t}: ${resultats.filter(r => r.type_destinataire === t).length}`);
});
console.log('═══════════════════════════════════════════════════\n');

return resultats.map(r => ({ json: r }));

const inputData = $input.all();

const TEMPLATES = {
  FRA: {
    sujet: {
      PDG:       '🔴 ALERTE URGENTE - Demandes d\'embauche non attachées',
      DGA:       '🟠 INFO DGA - Demandes à mi-délai non attachées',
      BAALLAH:   '🟠 INFO - Demandes à mi-délai non attachées',
      SUPERIEUR: '🟠 IMPORTANT - Demandes d\'embauche sans pièce jointe',
      SALARIE:   '🟡 Rappel - Demande en attente de complément',
      FARHAT:    '🔵 INFO PRÉVENTIVE - Demandes à surveiller'
    },
    intro: {
      PDG:       'ALERTE URGENTE - Les demandes d\'embauche suivantes n\'ont toujours pas de document attaché',
      DGA:       'Information - Les demandes suivantes ont atteint la moitié de leur délai sans traitement',
      BAALLAH:   'Information - Les demandes suivantes ont atteint la moitié de leur délai sans traitement',
      SUPERIEUR: 'Les demandes suivantes requièrent votre attention en priorité',
      SALARIE:   'Rappel concernant vos demandes en attente de traitement',
      FARHAT:    'Information préventive - Les demandes suivantes approchent de leur délai limite'
    },
    section_stats:   'STATISTIQUES',
    section_liste:   'LISTE DES DEMANDES CONCERNÉES',
    total:           'Total demandes',
    delai_min:       'Délai minimum restant',
    delai_total:     'Délai total paramétré',
    seuil_dga:       'Seuil mi-délai',
    jours:           'jour(s)',
    num_demande:     'N° Demande',
    nom_prenom:      'Nom & Prénom',
    matricule:       'Matricule',
    fonction:        'Fonction',
    date_creation:   'Date création',
    date_controle:   'Date contrôle',
    date_limite:     'Date limite',
    jours_restants:  'Jours restants',
    createur:        'Créé par',
    urgent:          'URGENT - Traitement immédiat requis',
    instruction:     'Veuillez traiter ces demandes dans les meilleurs délais.',
    instruction_dga: 'Ces demandes ont dépassé la moitié du délai autorisé. Merci de vous assurer que les actions correctives sont engagées.',
    cordialement:    'Cordialement',
    signature:       'Service SI/IA - Jbel Annour',
    message_auto:    'Message automatique',
    ne_pas_repondre: 'Merci de ne pas répondre à cet email'
  }
};

function formaterDate(d) {
  if (!d) return 'N/A';
  try { return new Date(d).toLocaleDateString('fr-FR', { year: 'numeric', month: '2-digit', day: '2-digit' }); }
  catch(e) { return String(d).substring(0, 10); }
}

function emoji(j) {
  if (j <= 2) return '🔴';
  if (j === 3) return '🟠';
  if (j === 4) return '🟡';
  if (j <= 8) return '🔵';
  return '🟢';
}

function genererEmail(data) {
  const T     = TEMPLATES['FRA'];
  const dest  = data.destinataire_principal;
  const stats = data.statistiques;
  const type  = data.type_destinataire;

  const subject = `${T.sujet[type]} - ${stats.total_demandes} demande(s)`;

  let body = `Bonjour ${dest.prenom || ''} ${dest.nom || ''},\n\n`;
  body += `${T.intro[type]}\n\n`;
  body += `═══════════════════════════════════════════════════════════════\n`;
  body += `📊 ${T.section_stats}\n`;
  body += `═══════════════════════════════════════════════════════════════\n\n`;
  body += `${emoji(stats.jours_min)} Niveau escalade : ${data.niveau_escalade}\n`;
  body += `${T.total} : ${stats.total_demandes}\n`;
  body += `${T.delai_min} : ${stats.jours_min} ${T.jours}\n`;
  body += `${T.delai_total} : ${stats.delai_int} ${T.jours}\n`;
  if (type === 'DGA' || type === 'BAALLAH') {
    body += `${T.seuil_dga} : ${stats.seuil_dga} ${T.jours}\n`;
  }

  body += `\n═══════════════════════════════════════════════════════════════\n`;
  body += `📋 ${T.section_liste}\n`;
  body += `═══════════════════════════════════════════════════════════════\n\n`;

  data.demandes.forEach((dem, i) => {
    body += `${i + 1}. ${emoji(dem.jours_restants)} N° ${dem.num_demande}\n`;
    body += `   👤 ${T.nom_prenom}    : ${dem.nom_prenom || 'N/A'}\n`;
    body += `   🏷️ ${T.matricule}    : ${dem.matricule && String(dem.matricule).trim() ? dem.matricule : 'Non attribué'}\n`;
    body += `   💼 ${T.fonction}     : ${dem.fonction || 'N/A'}\n`;
    body += `   📅 ${T.date_creation}: ${formaterDate(dem.date_creation)}\n`;
    if (dem.date_controle && !String(dem.date_controle).includes('1753')) {
      body += `   🗓️ ${T.date_controle}: ${formaterDate(dem.date_controle)}\n`;
    }
    body += `   ⏰ ${T.jours_restants}: ${dem.jours_restants} ${T.jours} (${T.date_limite} : ${formaterDate(dem.date_limite)})\n`;
    body += `   👤 ${T.createur}     : ${dem.createur.prenom || ''} ${dem.createur.nom || ''}\n`;
    if (dem.jours_restants <= 2) body += `   🚨 ${T.urgent}\n`;
    body += `\n`;
  });

  body += `═══════════════════════════════════════════════════════════════\n`;
  if (stats.jours_min <= 2) body += `🚨 ${T.urgent}\n`;
  else if (type === 'DGA' || type === 'BAALLAH') body += `📌 ${T.instruction_dga}\n`;
  else body += `📌 ${T.instruction}\n`;
  body += `═══════════════════════════════════════════════════════════════\n\n`;
  body += `${T.cordialement},\n\n${T.signature}\n\n`;
  body += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
  body += `🤖 ${T.message_auto} - ${formaterDate(new Date().toISOString())}\n`;
  body += `${T.ne_pas_repondre}\n`;

  return { subject, body };
}

function genererTelegram(data) {
  const T     = TEMPLATES['FRA'];
  const dest  = data.destinataire_principal;
  const stats = data.statistiques;
  const type  = data.type_destinataire;

  // ── EN-TÊTE ──────────────────────────────────────────────
  let text = `${emoji(stats.jours_min)} *${T.sujet[type]}*\n`;
  text += `━━━━━━━━━━━━━━━━━━━━━\n\n`;

  // ── DESTINATAIRE ─────────────────────────────────────────
  text += `📨 *Destinataire :* ${dest.prenom || ''} ${dest.nom || ''}\n`;
  text += `🏷️ *Niveau :* ${data.niveau_escalade}\n\n`;

  // ── STATISTIQUES ─────────────────────────────────────────
  text += `📊 *${T.section_stats}*\n`;
  text += `┣ ${T.total}: *${stats.total_demandes}*\n`;
  text += `┣ ${T.delai_min}: *${stats.jours_min} ${T.jours}*\n`;
  text += `┣ ${T.delai_total}: *${stats.delai_int} ${T.jours}*\n`;
  if (type === 'DGA' || type === 'BAALLAH') {
    text += `┗ ${T.seuil_dga}: *${stats.seuil_dga} ${T.jours}*\n`;
  } else {
    text += `┗ Date traitement: *${formaterDate(new Date().toISOString())}*\n`;
  }
  text += `\n`;

  // ── LISTE DES DEMANDES ────────────────────────────────────
  text += `📋 *${T.section_liste}*\n`;
  text += `━━━━━━━━━━━━━━━━━━━━━\n\n`;

  const demandesToShow = data.demandes.slice(0, 5);

  demandesToShow.forEach((dem, i) => {
    // Infos créateur en haut de chaque dossier
    const nomCreateur   = `${dem.createur.prenom || ''} ${dem.createur.nom || ''}`.trim() || 'N/A';

    text += `${i + 1}\\. ${emoji(dem.jours_restants)} *N° ${dem.num_demande}*\n`;
    text += `   👤 *Créateur :* ${nomCreateur}\n`;
    text += `   ─────────────────────\n`;
    text += `   👤 Candidat  : ${dem.nom_prenom || 'N/A'}\n`;
    text += `   🏷️ Matricule : ${dem.matricule && String(dem.matricule).trim() ? dem.matricule : 'Non attribué'}\n`;
    text += `   💼 Fonction  : ${dem.fonction || 'N/A'}\n`;
    text += `   📅 Créé le   : ${formaterDate(dem.date_creation)}\n`;
    if (dem.date_controle && !String(dem.date_controle).includes('1753')) {
      text += `   🗓️ Contrôle  : ${formaterDate(dem.date_controle)}\n`;
    }
    text += `   ⏰ Restant   : *${dem.jours_restants} ${T.jours}*\n`;
    text += `   📅 Limite    : ${formaterDate(dem.date_limite)}\n`;
    if (dem.jours_restants <= 2) text += `   🚨 *${T.urgent}*\n`;
    text += `\n`;
  });

  if (data.demandes.length > 5) {
    text += `_... et ${data.demandes.length - 5} autre(s) demande(s) non affichée(s)_\n\n`;
  }

  // ── CONCLUSION ────────────────────────────────────────────
  text += `━━━━━━━━━━━━━━━━━━━━━\n`;
  if (stats.jours_min <= 2) text += `🚨 *${T.urgent}*\n`;
  else if (type === 'DGA' || type === 'BAALLAH') text += `📌 ${T.instruction_dga}\n`;
  else text += `📌 ${T.instruction}\n`;
  text += `\n🤖 _${T.message_auto} - ${formaterDate(new Date().toISOString())}_\n`;

  return { text, parse_mode: 'MarkdownV2' };
}

const results = [];

inputData.forEach(item => {
  const data        = item.json;
  const emailMsg    = genererEmail(data);
  const telegramMsg = genererTelegram(data);

  // Message principal
  results.push({
    json: {
      ...data,
      messages: { email: emailMsg, telegram: telegramMsg },
      type_envoi: 'PRINCIPAL',
      destinataire_final: data.destinataire_principal,
      meta: { ...data.meta, date_generation: new Date().toISOString() }
    }
  });

  // CC Telegram : PDG → copie supérieur
  if (data.type_destinataire === 'PDG' && data.superieur?.chat_id) {
    results.push({ json: {
      ...data,
      messages: { email: emailMsg, telegram: telegramMsg },
      type_envoi: 'CC',
      destinataire_final: data.superieur,
      cc_pour_profil: 'SUPERIEUR',
      meta: { ...data.meta, date_generation: new Date().toISOString() }
    }});
  }

  // CC Telegram : PDG → copie créateur
  if (data.type_destinataire === 'PDG' && data.createur_info?.chat_id) {
    results.push({ json: {
      ...data,
      messages: { email: emailMsg, telegram: telegramMsg },
      type_envoi: 'CC',
      destinataire_final: data.createur_info,
      cc_pour_profil: 'SALARIE',
      meta: { ...data.meta, date_generation: new Date().toISOString() }
    }});
  }

  // CC Telegram : SUPERIEUR → copie créateur
  if (data.type_destinataire === 'SUPERIEUR' && data.createur_info?.chat_id) {
    results.push({ json: {
      ...data,
      messages: { email: emailMsg, telegram: telegramMsg },
      type_envoi: 'CC',
      destinataire_final: data.createur_info,
      cc_pour_profil: 'SALARIE',
      meta: { ...data.meta, date_generation: new Date().toISOString() }
    }});
  }
});

console.log(`\n✅ Messages générés: ${results.length}`);
console.log(`  - Principaux: ${results.filter(r => r.json.type_envoi === 'PRINCIPAL').length}`);
console.log(`  - CC Telegram: ${results.filter(r => r.json.type_envoi === 'CC').length}`);
['PDG','DGA','BAALLAH','SUPERIEUR','SALARIE','FARHAT'].forEach(t => {
  console.log(`  - ${t}: ${results.filter(r => r.json.type_destinataire === t).length}`);
});
console.log('═══════════════════════════════════════════════════\n');

return results;
